INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('aboriginal-57f41407-moex-00092', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-114-34c7f7f6', 'sub-aboriginal-57f41407-02', NULL, 'single_choice', '「有個故事是這樣說的：某天，老闆心血來潮召開全員大會。他問：『誰能說出公司現階段有哪些問 題？』大家反應踴躍，上百個人舉手。接著，老闆問：『為什麼會出現問題，誰能說出背後的原因？』 舉手的人立刻消失一半。老闆再問：『誰能告訴我解決方案？』還舉著手的剩不到二十個。老闆最後 問：『誰想動手試試看？』只剩下一個人還舉著手。」 根據上文，下列選項何者最符合文意？', '["批評是企業最佳的進步動力", "溝通是理解彼此最佳的方式", "找問題相較於解決問題更容易", "察言觀色是企業相當重視的能力"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:14+00:00", "source_pdf_sha1": "ec3d1305ccbd", "answer_pdf_sha1": "e298021d32ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00093', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-114-34c7f7f6', 'sub-aboriginal-57f41407-02', NULL, 'single_choice', '「從遠處觀望一個國家和社會時，我們為求便利常常會試圖簡化、一體化該國家或社會裡所有的人。 然而若我們把鏡頭不斷拉近，就會看到截然不同的個人，在民主越發達的社會，越是如此。」 根據上文，下列選項最符合旨意的是：', '["透過遠觀與近看，我們才能掌握民主發達的社會", "在民主社會中個體差異存在明顯，很難概括而論", "極權社會相較於民主社會常被統治者要求一體化", "看待事情的角度，鏡頭拉遠較客觀，拉近較主觀"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:14+00:00", "source_pdf_sha1": "ec3d1305ccbd", "answer_pdf_sha1": "e298021d32ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00094', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-114-34c7f7f6', 'sub-aboriginal-57f41407-02', NULL, 'single_choice', '「『能樂』初訪歐陸時，歐洲人將其視為粗糙不入耳的噪音，並且認為『能樂』毫無音樂性。法國音 樂家布列茲指出：一些法國演員模仿日本能劇演員，因為對『能樂』的規則和意義缺乏了解，所以他 們的模仿淪為誇大與諧謔，錯過了『能樂』蘊含的戲劇意涵。他同時也說道：一個能樂演員即便擁有 再精巧的聲音技術，也不可能符合阿拉伯歌手的標準。」 根據上文，下列選項最符合文意的是：', '["不同文化背景，對音樂的接受與詮釋，可能存在極大差異", "對藝術創作的文化背景若缺乏認識，可以用聲音技術補足", "雖然音樂的形式千差萬別，但聲音演出者的條件沒有不同", "演出者只要透過適當訓練，便能精準表現出異文化的作品"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:14+00:00", "source_pdf_sha1": "ec3d1305ccbd", "answer_pdf_sha1": "e298021d32ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00095', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-114-34c7f7f6', 'sub-aboriginal-57f41407-02', NULL, 'single_choice', '「我喜歡把城市的綠地當做沙漠的綠洲，海洋中的島嶼。植物園正是這樣的城中島，而且是臺北城裡 生物資源最為豐富的自然生態島嶼。……我也想建議，喜歡觀賞樹木的人，不妨注意植物園的烏桕和 相思樹，看看這兩種低海拔常見樹種，七、八十歲時，年紀垂老的模樣。在北部近郊山區，我們看到 的相思樹和烏桕總是太年輕，察覺不出歷史和人文的風味。」 根據上文，下列選項何者最符合文意？', '["植物園裡的樹木多半已是垂老樹種", "水泥叢林聳立的臺北城儼然是沙漠", "觀賞自然物種，不一定要上山才能享受", "人工化的植物園，察覺不出歷史與人文"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:14+00:00", "source_pdf_sha1": "ec3d1305ccbd", "answer_pdf_sha1": "e298021d32ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00096', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-114-34c7f7f6', 'sub-aboriginal-57f41407-02', NULL, 'single_choice', '「胡適先生曾說過：『有一分證據，說一分話。』當有人質疑，你就必須提出證據。如班長走進教室， 大聲宣布：期末考取消了！這時候，同學們會立即反應『真的假的？』類似這樣的場景，日常生活中 時常可見。班長講的話，資訊不夠，欠缺『發言依據』。得透過其他的詞彙、語句，把那句話『補充』 得更加可信。像是：老師要我跟大家說，期末考取消了！」 下列選項，何者最符合言之有據的溝通方式？', '["他說今天可以不用加班了", "主管交代今日的會議延期", "聽說今日的主管會議取消了", "我覺得工作會報將延期舉辦"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:14+00:00", "source_pdf_sha1": "ec3d1305ccbd", "answer_pdf_sha1": "e298021d32ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00097', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-114-34c7f7f6', 'sub-aboriginal-57f41407-02', NULL, 'single_choice', '「樹木生長的主要特徵之一是樹輪的形成與變異，這除了受到樹木本身的遺傳因子控制外，也受到環 境的制約。樹輪不僅能用來判定年代，更像是環境的紀錄器，可供探討過去數百年至數千年來各種環 境因子的變化，包括氣候、水文、環境汙染、地震、火山、部落遷徙等問題。」 根據上文，下列選項何者最符合文意？', '["樹輪越多的樹木，代表受環境制約的影響越大", "樹木影響了周遭的環境，所以形成不同的輪紋", "透過樹輪樣貌，可以推測過去環境汙染的變化", "科學家觀察樹輪，能預測未來火山爆發的頻率"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:14+00:00", "source_pdf_sha1": "ec3d1305ccbd", "answer_pdf_sha1": "e298021d32ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00098', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-114-34c7f7f6', 'sub-aboriginal-57f41407-02', NULL, 'single_choice', '「某天農夫的驢子，不小心掉進枯井裡，他費盡心思想救出驢子，但過了幾個小時，驢子還在井裡痛 苦地哀嚎著。最後，農夫想到這頭驢子年紀大了，不值得大費周章救出來，決定放棄，但為了安全， 這口井還是必須填平。農夫請來友人幫忙填井，當泥土不斷被鏟進枯井中，驢子似乎了解到自己的處 境，一開始很悽慘的哀叫著，但一會兒後驢子就安靜下來。農夫好奇地往井底看，令他大吃一驚：當 泥土落在驢背時，驢子立即將身上的泥土抖落，接著就站在抖落的泥土堆上。驢子一次又一次將泥土 抖落在井底，然後再站上去。沒多久便上升到井口，然後在眾人驚訝中很快逃走了。」 根據上述故事，下列選項何者最符合文意？', '["上天有好生之德，人心無不轉之時", "向來枉費推移力，此日中流自在行", "車到山前必有路，船到橋頭自然直", "泰山崩前色不變，麋鹿興左目不瞬"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:14+00:00", "source_pdf_sha1": "ec3d1305ccbd", "answer_pdf_sha1": "e298021d32ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00099', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-114-34c7f7f6', 'sub-aboriginal-57f41407-02', NULL, 'single_choice', '「開發中國家的人民只是嘗試要享受我們已經在享受的消耗率。如果我們傻到告訴他們不要試圖做我 們已經在做的事，他們絕不會聽。在全球化的世界中，開發中國家會接受的唯一可能，是全球各地的 消耗率和生活水準更加接近。但地球並沒有足夠的資源持續支持當前第一世界的消耗率，遑論支持開 發中國家採用當前第一世界的消耗率。這是否意味我們最後必然會陷入災難？不，只要第一世界和其 他國家能夠攜手，讓消耗率降到遠低於當前第一世界的消耗率，我們就可以獲得穩定的結果。」 根據上文，「消耗率」是指：', '["維持生命最低限度所必要的能量之「基礎代謝率」", "身體一天之內所消耗的熱量之「每日總熱量消耗」", "各類運動半小時消耗的熱量之「運動消耗卡路里」", "每一國人民所消耗的石油等資源之「人均消耗率」"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:14+00:00", "source_pdf_sha1": "ec3d1305ccbd", "answer_pdf_sha1": "e298021d32ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00100', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-114-34c7f7f6', 'sub-aboriginal-57f41407-02', NULL, 'single_choice', '承上題，下列選項何者最符合文意？', '["消耗率高代表生活水準就一定高", "避免陷入災難較可行的方法是第一世界率先降低消耗率", "開發中國家唯利是圖，遂不願放棄享受第一世界已在享受的消耗率", "地球的資源只夠持續支持當前第一世界或開發中國家二者之一享受的消耗率"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:14+00:00", "source_pdf_sha1": "ec3d1305ccbd", "answer_pdf_sha1": "e298021d32ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00101', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-114-1611a566', 'sub-aboriginal-57f41407-03', NULL, 'single_choice', '關於法院，下列敘述何者錯誤？', '["民事訴訟法所定之法院，是指職司審判工作之法官組成的裁判機關", "裁判機關之法院，有分獨任制或合議制，獨任制係指由1位法官審理，合議制則是由5位法官組成 合議庭審理", "行合議審判事件可先由受命法官行準備程序，包括確定雙方聲明、權利主張、事實主張、證據聲明 及進行爭點整理", "行合議審判事件於言詞辯論程序必須由合議庭全部法官出庭加以審理"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:14+00:00", "source_pdf_sha1": "0f8f6099d55e", "answer_pdf_sha1": "a6db6dc8e7be", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0807", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL)
